command_failures.command:
/bin/zsh -lc "docker compose -f infra/compose/docker-compose.yml exec -T browser node --input-type=module - <<'EOF'
import fs from 'node:fs/promises';
import puppeteer from 'puppeteer';

const sessionId = '464fe382-f23a-4f03-9dce-fffc86a4f080';
const outputDir = '/workspace/tools/webapp-qa/.artifacts/prompt-70';
await fs.mkdir(outputDir, { recursive: true });

const browser = await puppeteer.launch({
  headless: true,
  executablePath: process.env.PUPPETEER_EXECUTABLE_PATH,
  args: ['--no-sandbox', '--disable-setuid-sandbox'],
});

async function scrollAudioStageIntoView(page) {
  await page.waitForFunction(() => document.body?.innerText.includes('Shape the narration pass before the audio render starts.'));
  await page.evaluate(() => {
    const heading = Array.from(document.querySelectorAll('h3')).find((node) =>
      node.textContent?.includes('Shape the narration pass before the audio render starts.'),
    );
    if (heading) {
      heading.scrollIntoView({ block: 'start', behavior: 'instant' });
      window.scrollBy(0, -24);
    }
  });
  await page.waitForTimeout(300);
}

async function verifyAndShoot({ width, height, name }) {
  const page = await browser.newPage();
  page.setDefaultTimeout(20000);
  await page.setViewport({ width, height });
  await page.goto("'`http://frontend:8566/sessions/${sessionId}`, { waitUntil: '"'networkidle2' });
  await page.waitForSelector('[data-testid=\"workspace-route\"]');
  await page.waitForFunction(() => document.body?.innerText.includes('About 15 min'));
  await page.waitForFunction(() => document.body?.innerText.includes('Hearthside'));
  await page.waitForFunction(() => document.body?.innerText.includes('Night ambience'));
  await page.waitForFunction(() => document.body?.innerText.includes('Save audio settings'));
  await scrollAudioStageIntoView(page);
  await page.screenshot({ path: "'`${outputDir}/${name}.png`, fullPage: false });
  await page.close();
}

await verifyAndShoot({ width: 1440, height: 960, name: '"'audio-settings-desktop' });
await verifyAndShoot({ width: 430, height: 932, name: 'audio-settings-mobile' });

await browser.close();
console.log("'`${outputDir}/audio-settings-desktop.png`);
console.log(`${outputDir}/audio-settings-mobile.png`);
EOF'
